using System.Collections.Generic;namespace EditorBrowser{    /// <summary>    /// ?⑥닚 ?ㅻ줈/?욎쑝濡??ㅻ퉬寃뚯씠???덉뒪?좊━.    /// 釉뚮씪?곗? ?쒖? ?숈옉??留욎떠 forward ?꾩튂?먯꽌 ??Push ??forward ?덉뒪?좊━???섎씪?몃떎.    /// ?꾩옱??UI ?곹깭 愿由ъ슜 ???댄썑 ?몃? 釉뚮씪?곗? ?몄뒪?몄? ?숆린?붾맆 ?덉젙.    /// </summary>    internal sealed class BrowserHistory    {        private readonly List<string> _entries = new List<string>();        private int _index = -1;        /// <summary>?꾩옱 ?꾩튂??URL. 鍮꾩뼱 ?덉쑝硫?null.</summary>        public string Current => (_index >= 0 && _index < _entries.Count) ? _entries[_index] : null;        public bool CanGoBack => _index > 0;        public bool CanGoForward => _index >= 0 && _index < _entries.Count - 1;        public int Count => _entries.Count;        /// <summary>        /// ??URL???덉뒪?좊━??異붽?. 媛숈? URL ?곗냽 push??臾댁떆.        /// ?꾩옱 ?꾩튂媛 ?앹씠 ?꾨땲硫?洹??ㅼ쓽 forward ?덉뒪?좊━瑜??섎씪?몃떎.        /// </summary>        public void Push(string url)        {            if (string.IsNullOrEmpty(url)) return;            if (Current == url) return;            if (_index < _entries.Count - 1)                _entries.RemoveRange(_index + 1, _entries.Count - _index - 1);            _entries.Add(url);            _index = _entries.Count - 1;        }        public string GoBack()        {            if (!CanGoBack) return Current;            _index--;            return Current;        }        public string GoForward()        {            if (!CanGoForward) return Current;            _index++;            return Current;        }        public void Clear()        {            _entries.Clear();            _index = -1;        }    }}